import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        if (n == 1) return 0;

        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));

        long max_w = edges[edges.length - 1][2];

        class DSU {
            long[] parent;
            long[] rank;

            DSU(long size) {
                parent = new long[size];
                rank = new long[size];
                for (long i = 0; i < size; i++) {
                    parent[i] = i;
                    rank[i] = 1;
                }
            }

            long find(long x) {
                if (parent[x] != x) {
                    parent[x] = find(parent[x]);
                }
                return parent[x];
            }

            void union(long x, long y) {
                long x_root = find(x);
                long y_root = find(y);
                if (x_root == y_root) return;
                if (rank[x_root] < rank[y_root]) {
                    parent[x_root] = y_root;
                } else {
                    parent[y_root] = x_root;
                    rank[x_root] += rank[y_root];
                }
            }
        }

        long low = 1;
        long high = max_w;
        long answer = max_w;

        while (low <= high) {
            long mid = (low + high) / 2;
            DSU dsu = new DSU(n);
            for (long[] edge : edges) {
                if (edge[2] <= mid) {
                    dsu.union(edge[0], edge[1]);
                }
            }

            Set<Long> roots = new HashSet<>();
            for (long i = 0; i < n; i++) {
                roots.add(dsu.find(i));
            }
            long component_count = roots.size();

            if (component_count <= k) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return answer;
    }
}
